// Solution
#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
int binarySearch(vector<int>& arr, int target) {
    int left = 0, right = arr.size() - 1;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (arr[mid] == target) {
            return mid;
        } else if (arr[mid] < target) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }
    return -1;
};
};
int main() {
    Solution solution;
    vector<int> arr = {1, 2, 3, 4, 5, 6};
    int target = 3;
    cout << solution.binarySearch(arr, target) << endl;
    return 0;
}

