// Solution
import sys
class Solution:

def binary_search(self, arr, target):
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = left + (right - left) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1
if __name__ == '__main__':
    solution = Solution()
    arr = [1, 2, 3, 4, 5, 6]
    target = 3
    print(solution.binary_search(arr, target))

